ROOT CAUSE: The `server.listen()` call doesn't have any error handling for port binding conflicts. When the port is already in use, Node.js throws an unhandled exception that crashes the entire process instead of allowing graceful failure.

FIX:
```ts
export function startSseServer(taskStore: TaskStore): http.Server {
    const server = http.createServer((req, res) => { /* ... request handling ... */ });

    const SSE_PORT = parseInt(process.env["SSE_PORT"] ?? "3001", 10);
    const SSE_HOST = process.env["SSE_HOST"] ?? "127.0.0.1";

    server.listen(SSE_PORT, SSE_HOST, () => {
        logger.info({ host: SSE_HOST, port: SSE_PORT }, "SSE server listening");
    });

    server.on('error', (err) => {
        if ('code' in err && err.code === 'EADDRINUSE') {
            logger.warn({ host: SSE_HOST, port: SSE_PORT }, "SSE server port in use, skipping SSE");
            return;
        }
        throw err; // Re-throw if it's a different error
    });

    return server;
}
```

